sql:
SELECT COUNT(*) AS access_count
FROM pin_access_logs
WHERE user_id = 0;

SELECT COUNT(test_id) AS test_count
FROM pin_test_results
WHERE pin_id = 1;

SELECT pin_id, test_result
FROM pin_test_results
WHERE test_date = '2023-05-01';

SELECT access_description
  FROM pin_access_logs
  WHERE access_type = 'update';

